/**
 * Calculates (base^exp) % mod
 * @param {bigint} base
 * @param {bigint} exp
 * @param {bigint} mod
 * @returns {bigint}
 */
function power(base, exp, mod) {
    let res = 1n;
    base %= mod;
    while (exp > 0n) {
        if (exp % 2n === 1n) {
            res = (res * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2n;
    }
    return res;
}

/**
 * Calculates nCk % mod
 * @param {number} n
 * @param {number} k
 * @param {bigint} mod
 * @param {bigint[]} fact Precomputed factorials
 * @param {bigint[]} invFact Precomputed inverse factorials
 * @returns {bigint}
 */
function nCk_mod(n, k, mod, fact, invFact) {
    if (k < 0 || k > n) {
        return 0n;
    }
    return (((fact[n] * invFact[k]) % mod) * invFact[n - k]) % mod;
}

/**
 * Solves the problem by counting combinations using precomputed factorials and modular inverse.
 * @param {number} n Total number of people.
 * @param {number} pos Position of the reference person.
 * @param {number} k Target number of visible people.
 * @returns {number} The number of possible direction assignments modulo 10^9 + 7.
 */
function solve(n, pos, k) {
    const MOD = 1000000000 + 7;
    const MOD_BIGINT = 1000000000n + 7n;

    // Number of people to the left of pos (indices 0 to pos - 1)
    const leftCount = pos;
    // Number of people to the right of pos (indices pos + 1 to n - 1)
    const rightCount = n - 1 - pos;

    // The person at pos can choose 'L' or 'R' (2 options), which doesn't affect the count k.
    // We only need to count configurations for the other n-1 people.

    // Visibility rules for pos:
    // 1. i < pos (left): Visible if i chooses 'L'. (Total leftCount people)
    // 2. i > pos (right): Visible if i chooses 'R'. (Total rightCount people)

    // Let k_L be the number of people on the left who choose 'L' (visible).
    // Let k_R be the number of people on the right who choose 'R' (visible).
    // We need k_L + k_R = k.

    // Precompute factorials and inverse factorials up to n
    const MAX_N = n;
    const fact = new Array(MAX_N + 1);
    const invFact = new Array(MAX_N + 1);

    fact[0] = 1n;
    for (let i = 1; i <= MAX_N; i++) {
        fact[i] = (fact[i - 1] * BigInt(i)) % MOD_BIGINT;
    }

    // Modular inverse of fact[MAX_N] using Fermat's Little Theorem
    const invFact_max = power(fact[MAX_N], MOD_BIGINT - 2n, MOD_BIGINT);
    invFact[MAX_N] = invFact_max;

    // Compute remaining inverse factorials iteratively
    for (let i = MAX_N - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * BigInt(i + 1)) % MOD_BIGINT;
    }

    let totalWays = 0n;

    // Iterate over all possible ways to split k into k_L + k_R
    // k_L must be between 0 and leftCount
    // k_R must be between 0 and rightCount

    const max_k_L = Math.min(k, leftCount);

    for (let k_L = 0; k_L <= max_k_L; k_L++) {
        const k_R = k - k_L;

        // Check if k_R is valid
        if (k_R < 0 || k_R > rightCount) {
            continue;
        }

        // 1. Ways to choose k_L visible people on the left:
        // Among leftCount people, we choose k_L to choose 'L' (visible).
        // The remaining (leftCount - k_L) people must choose 'R' (invisible).
        // Ways_L = C(leftCount, k_L)
        const waysL = nCk_mod(leftCount, k_L, MOD_BIGINT, fact, invFact);

        // 2. Ways to choose k_R visible people on the right:
        // Among rightCount people, we choose k_R to choose 'R' (visible).
        // The remaining (rightCount - k_R) people must choose 'L' (invisible).
        // Ways_R = C(rightCount, k_R)
        const waysR = nCk_mod(rightCount, k_R, MOD_BIGINT, fact, invFact);

        // Total ways for this split k_L, k_R
        let waysForSplit = (waysL * waysR) % MOD_BIGINT;

        // Contribution to total: waysForSplit * 2 (for pos's choice)
        // The person at pos has 2 choices ('L' or 'R'), regardless of k.
        let contribution = (waysForSplit * 2n) % MOD_BIGINT;

        totalWays = (totalWays + contribution) % MOD_BIGINT;
    }

    // Return the result as a standard JS number (since it fits within standard integer limits after modulo)
    return Number(totalWays);
}

