import java.util.Arrays;

public class Solution {
    private static final long MOD = 1_000_000_007L;

    // Calculates (base^exp) % mod
    private static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }

    // Calculates modular inverse of n modulo MOD
    private static long modInverse(long n) {
        return power(n, MOD - 2);
    }

    // Global arrays for precomputed factorials and inverse factorials
    private static long[] fact;
    private static long[] invFact;

    private static void precomputeFactorials(int maxN) {
        fact = new long[maxN + 1];
        invFact = new long[maxN + 1];
        fact[0] = 1;
        for (int i = 1; i <= maxN; i++) {
            fact[i] = (fact[i - 1] * i) % MOD;
        }
        invFact[maxN] = modInverse(fact[maxN]);
        for (int i = maxN - 1; i >= 0; i--) {
            invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
        }
    }

    // Calculates nCk % MOD
    private static long nCkMod(int n, int k) {
        if (k < 0 || k > n) {
            return 0;
        }
        // nCk = n! / (k! * (n-k)!)
        long numerator = fact[n];
        long denominator = (invFact[k] * invFact[n - k]) % MOD;
        return (numerator * denominator) % MOD;
    }

    public static long solve(long n, long pos, long k) {
        if (n == 0) return 0;

        int N = (int) n;
        int P = (int) pos;
        int K = (int) k;

        // Precompute factorials up to N
        precomputeFactorials(N);

        // Number of people to the left of pos (indices 0 to pos - 1)
        int leftCount = P;
        // Number of people to the right of pos (indices pos + 1 to n - 1)
        int rightCount = N - 1 - P;

        // Visibility rules:
        // Left (i < pos): Visible if i chooses 'L'. Max visible = leftCount.
        // Right (i > pos): Visible if i chooses 'R'. Max visible = rightCount.
        // We need k_L + k_R = K.

        long totalWays = 0;

        // Iterate over all possible ways to split K into k_L + k_R
        // k_L must be between 0 and min(K, leftCount)
        int max_k_L = Math.min(K, leftCount);

        for (int k_L = 0; k_L <= max_k_L; k_L++) {
            int k_R = K - k_L;

            // Check if k_R is valid
            if (k_R < 0 || k_R > rightCount) {
                continue;
            }

            // 1. Ways to choose k_L visible people on the left:
            // Choose k_L people out of leftCount to choose 'L'. C(leftCount, k_L)
            long waysL = nCkMod(leftCount, k_L);

            // 2. Ways to choose k_R visible people on the right:
            // Choose k_R people out of rightCount to choose 'R'. C(rightCount, k_R)
            long waysR = nCkMod(rightCount, k_R);

            // Total ways for this split k_L, k_R
            long waysForSplit = (waysL * waysR) % MOD;

            // The person at pos has 2 choices ('L' or 'R'), regardless of the count K.
            // Contribution = waysForSplit * 2
            long contribution = (waysForSplit * 2) % MOD;

            totalWays = (totalWays + contribution) % MOD;
        }

        return totalWays;
    }
}
